const staticData = $getWorkflowStaticData('global');
if (!staticData.importedIds) staticData.importedIds = [];

const body = $input.first().json.body || $input.first().json;
const id = String(body.recording_id || body.id || '');

if (!id) throw new Error('Fathom webhook: missing recording_id in payload');
if (staticData.importedIds.includes(id)) {
  return [{ json: { skip: true, reason: 'already imported', id } }];
}
return [{ json: { skip: false, body } }];

const item = $input.first().json.body || $input.first().json;

const rawDate = item.scheduled_start_time || item.created_at || new Date().toISOString();
const dateStr = new Date(rawDate).toISOString().split('T')[0];
const title = item.meeting_title || item.title || 'Untitled Meeting';
const safeTitle = title.toLowerCase().replace(/[^a-z0-9\s]+/g,'').trim().replace(/\s+/g,'-').substring(0,60);
const filename = dateStr + '-' + safeTitle + '.md';

const rawSummary = (item.default_summary && item.default_summary.markdown_formatted) || '';
const summary = rawSummary.replace(/\[([^\]]+)\]\(https:\/\/fathom\.video\/[^)]+\)/g,'$1').trim() || '_No summary._';

const lines = item.transcript || [];
let transcriptText = '';
for (const line of lines) {
  const speaker = (line.speaker && line.speaker.display_name) ? line.speaker.display_name : 'Unknown';
  const words = (line.words || []).map(w => w.text).join(' ').trim();
  if (words) transcriptText += `**${speaker}**: ${words}\n\n`;
}
const shareUrl = item.share_url || '';
const transcriptSection = transcriptText.length > 1200
  ? transcriptText.substring(0,1200).trimEnd() + '\n\n_[truncated — full: ' + shareUrl + ']_'
  : (transcriptText || '_No transcript._');

const actions = item.action_items || [];
const actionLines = actions.length
  ? actions.map(a => '- [ ] ' + (typeof a === 'string' ? a : (a.description || JSON.stringify(a)))).join('\n')
  : '- [ ] None identified';

const fathomUrl = item.share_url || item.url || '';
const markdown = '# ' + title + '\n\nDate: ' + dateStr + '\nFathom: ' + fathomUrl + '\n\n## Summary\n' + summary + '\n\n## Action Items\n' + actionLines + '\n\n## Raw Transcript\n' + transcriptSection + '\n';

return [{ json: { recording_id: String(item.recording_id || ''), title, markdown, filename, dateStr } }];

const item = $input.first().json;
const encoded = Buffer.from(item.markdown, 'utf8').toString('base64');
return [{ json: { ...item }, binary: { fileData: { data: encoded, mimeType: 'text/markdown', fileName: item.filename, fileExtension: 'md' } } }];

const staticData = $getWorkflowStaticData('global');
if (!staticData.importedIds) staticData.importedIds = [];
const id = String($input.first().json.recording_id || '');
if (id && !staticData.importedIds.includes(id)) staticData.importedIds.push(id);
return [{ json: { ok: true, file: $input.first().json.filename } }];

